func TestEnumLocationCapability(t *testing.T) {
	t.Run("NewFromString_CREDIT_CARD_PROCESSING", func(t *testing.T) {
		t.Parallel()
		val, err := NewLocationCapabilityFromString("CREDIT_CARD_PROCESSING")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, LocationCapability("CREDIT_CARD_PROCESSING"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_AUTOMATIC_TRANSFERS", func(t *testing.T) {
		t.Parallel()
		val, err := NewLocationCapabilityFromString("AUTOMATIC_TRANSFERS")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, LocationCapability("AUTOMATIC_TRANSFERS"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_UNLINKED_REFUNDS", func(t *testing.T) {
		t.Parallel()
		val, err := NewLocationCapabilityFromString("UNLINKED_REFUNDS")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, LocationCapability("UNLINKED_REFUNDS"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewLocationCapabilityFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewLocationCapabilityFromString("CREDIT_CARD_PROCESSING")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

